INSERT INTO public.stoic_quotes (text, author, source, language) VALUES
('Tienes poder sobre tu mente, no sobre los eventos externos. Date cuenta de esto y encontrarás la fuerza.', 'Marco Aurelio', 'Meditaciones', 'es'),
('No desperdicies lo que queda de tu vida en pensamientos sobre otras personas cuando no estás pensando en el bien común.', 'Marco Aurelio', 'Meditaciones', 'es'),
('La calidad de tu vida depende de la calidad de tus pensamientos.', 'Marco Aurelio', 'Meditaciones', 'es'),
('No te aferres a lo que no está en tu poder. La felicidad está en tu interior.', 'Epicteto', 'Enquiridion', 'es'),
('Hace que el mejor uso de lo que está en tu poder, y toma el resto como sucede.', 'Epicteto', 'Enquiridion', 'es'),
('No es que tengamos poco tiempo, sino que desperdiciamos mucho.', 'Séneca', 'Sobre la brevedad de la vida', 'es'),
('Ningún viento es favorable para el marinero que no sabe adónde va.', 'Séneca', 'Cartas a Lucilio', 'es'),
('Divide tu vida en partes: examina cada una separadamente y la vida no te parecerá tan larga.', 'Séneca', 'Cartas a Lucilio', 'es'),
('La dificultad muestra lo que son los hombres.', 'Epicteto', 'Discursos', 'es'),
('Vive como si murieras ahora mismo, y luego, a vivir en la manera que siempre deseaste.', 'Marco Aurelio', 'Meditaciones', 'es');
